import{_ as t,c as e,o as a,ag as i}from"./chunks/framework.S-Qvb3wi.js";const h=JSON.parse('{"title":"DGrid 제네시스 멤버십 인센티브 메커니즘 및 보상 설명","description":"","frontmatter":{},"headers":[],"relativePath":"kr/Incentive-Mechanism-&-Rewards.md","filePath":"kr/Incentive-Mechanism-&-Rewards.md"}'),n={name:"kr/Incentive-Mechanism-&-Rewards.md"};function o(s,r,l,d,c,p){return a(),e("div",null,r[0]||(r[0]=[i('<h1 id="dgrid-제네시스-멤버십-인센티브-메커니즘-및-보상-설명" tabindex="-1">DGrid 제네시스 멤버십 인센티브 메커니즘 및 보상 설명 <a class="header-anchor" href="#dgrid-제네시스-멤버십-인센티브-메커니즘-및-보상-설명" aria-label="Permalink to &quot;DGrid 제네시스 멤버십 인센티브 메커니즘 및 보상 설명&quot;">​</a></h1><p>DGrid는 제네시스 멤버를 위해 $DGAI 토큰을 핵심으로 한 장기 인센티브 시스템을 맞춤 설계했으며, 멤버와 생태계의 가치 연계를 실현하여 초기 지지자가 네트워크 성장이 가져오는 풍부한 혜택을 충분히 공유할 수 있도록 한다.</p><h3 id="핵심-인센티브-제네시스-공동-구축-보상" tabindex="-1">핵심 인센티브: 제네시스 공동 구축 보상 <a class="header-anchor" href="#핵심-인센티브-제네시스-공동-구축-보상" aria-label="Permalink to &quot;핵심 인센티브: 제네시스 공동 구축 보상&quot;">​</a></h3><ul><li><strong>tDGAI &amp; IOTX 토큰 보상</strong></li></ul><p>제네시스 멤버 자격을 보유하는 기간 동안 별도의 업무 없이도 지속적인 tDGAI &amp; IOTX 토큰 보상을 자동으로 받을 수 있다. 보상의 총 가치는 DGrid 생태계의 활성도와 강력하게 연계되어 있으며, 네트워크 내 사용자, 모델 및 컴퓨팅 작업의 지속적인 성장과 함께 동기 부여되어 <strong>「보유만으로 수동 수익을 얻을 수 있는」</strong> 효과를 실현한다.</p><ul><li><strong>2% 추천 리베이트 보상</strong></li></ul><p>제네시스 멤버는 전용 추천 링크를 받을 수 있다. 신규 사용자를 성공적으로 초대하여 제네시스 멤버를 구매하고 활성화하면, 추천인은 피추천인의 구매 금액의 2%에 해당하는 USDT 리베이트를 받을 수 있다. 리베이트는 자동으로 입금되며, 대시보드의 <strong><a href="https://premium.dgrid.ai/referral" target="_blank" rel="noreferrer">친구 추천</a></strong> 전용 구역에서 기록을 확인하고 출금할 수 있다.</p><h3 id="tdgai-및-iotx-보상-수령-튜토리얼" tabindex="-1">tDGAI 및 IOTX 보상 수령 튜토리얼 <a class="header-anchor" href="#tdgai-및-iotx-보상-수령-튜토리얼" aria-label="Permalink to &quot;tDGAI 및 IOTX 보상 수령 튜토리얼&quot;">​</a></h3><p>제네시스 멤버는 DGrid 대시보드를 통해 간편하게 tDGAI와 IOTX 보상을 수령할 수 있으며, 구체적인 단계는 다음과 같다:</p><ol><li>​<strong>로그인 인증</strong>​: 제네시스 패스가 바인딩된 지갑으로 DGrid 공식 대시보드에 로그인하고, 지갑 서명 인증을 완료한다(수수료 지불 불필요).</li><li>​**「제네시스 보상」 전용 구역 진입**​: 「내 보상」을 찾으면 시스템이 수령 가능한 tDGAI와 IOTX 보상 수량을 자동으로 표시한다. 정보를 확인한 후 「수령」 버튼을 클릭한다.</li><li>​<strong>입금 확인</strong>​: 수령 작업 완료 후 보상은 바인딩된 지갑으로 지급된다. 대시보드의 「수령 기록」 또는 지갑 탐색기를 통해 입금 상태를 확인할 수 있다.</li></ol><blockquote><p>​<strong>참고​</strong>​: tDGAI는 DGAI 토큰의 테스트 버전으로, DGrid 테스트 네트워크에서 각종 기능을 체험하는 데 사용할 수 있다. IOTX 보상은 생태계 협력 보상으로, 제네시스 멤버 자격이 활성화 상태를 유지해야만 수령할 수 있다.</p></blockquote>',11)]))}const g=t(n,[["render",o]]);export{h as __pageData,g as default};
